    cd_priv_export_li2:"<strong>PDF</strong> - Generate formatted reports of your transactions",
    cd_priv_export_li3:"<strong>JSON</strong> - Export raw data for personal backup or migration",
    cd_priv_export_li4:"<strong>CSV</strong> - Export in comma-separated format for use in other applications",
    cd_priv_export_p2:"Exported files are saved to your device's local storage. These files are <strong>not uploaded to any server</strong> by the App. You are responsible for managing and securing exported files.",
    cd_priv_gsign_h:"Google Sign-In",
