Object.keys(CASHDIARY_LANGS).forEach(function(k){if(LANGS[k])Object.assign(LANGS[k],CASHDIARY_LANGS[k])});
(function(){
  var originalSetLang=setLang;
  setLang=function(lang){
    originalSetLang(lang);
    if(window.location.pathname.indexOf("/apps/cashdiary/privacy")!==-1||window.location.pathname.indexOf("\\apps\\cashdiary\\privacy")!==-1){
      var o=LANGS[lang];
      if(!o)return;
      var title=o.cd_priv_meta_title,desc=o.cd_priv_meta_description;
      if(title){
        document.title=title;
        var ogt=document.querySelector('meta[property="og:title"]');if(ogt)ogt.setAttribute("content",title);
        var twt=document.querySelector('meta[name="twitter:title"]');if(twt)twt.setAttribute("content",title);
      }
      if(desc){
        var md=document.querySelector('meta[name="description"]');if(md)md.setAttribute("content",desc);
        var ogd=document.querySelector('meta[property="og:description"]');if(ogd)ogd.setAttribute("content",desc);
        var twd=document.querySelector('meta[name="twitter:description"]');if(twd)twd.setAttribute("content",desc);
      }
    }
  };
})();
